import unittest

class TestSolveForX(unittest.TestCase):
    
    def test_positive_solution(self):
        # Test case with a positive solution
        self.assertEqual(solve_for_x('x - 5 = 20'), 25)
        
    def test_negative_solution(self):
        # Test case with a negative solution
        self.assertEqual(solve_for_x('20 = 5 * x - 5'), 5)
        
    def test_zero_solution(self):
        # Test case with a zero solution
        self.assertEqual(solve_for_x('5 * x = x + 8'), 2)
        
    def test_complex_solution(self):
        # Test case with a more complex solution
        self.assertEqual(solve_for_x('(5 - 3) * x = x + 2'), 2)
        
    def test_no_solution(self):
        # Test case with no solution
        self.assertIsNone(solve_for_x('2 * x + 3 = 2 * x + 3'), None)
        
